import Tea from '@dp/byted-tea-sdk-oversea/es/index-base.min';

const MAP_APPID = {
  CN: 3053,
  OVERSEA: 3297, // 接入 ET 和 TEA 选择的新加坡。
};

export type channel_type = 'ttp' | 'tcpy';
export type channel = 'va' | 'sg' | 'in';

function createTracker(options: {
  isTest: boolean;
  channel?: channel;
  channel_type?: channel_type;
  channel_domain?: string;
}) {
  const { isTest, channel_domain, channel_type, channel } = options;
  const isCn =
    /snssdk|zijieapi/g.test(channel_domain) &&
    /ttp|tcpy/g.test(channel_type) &&
    /va|sg|in/g.test(channel);
  const appId = isCn ? MAP_APPID.CN : MAP_APPID.OVERSEA;

  Tea.init({
    app_id: appId,
    channel_type,
    channel,
    channel_domain,
  });

  Tea.config({
    _staging_flag: isTest ? 1 : 0, // 是否发到测试环境
    enable_et_test: isTest, // 是否启用埋点验证
  });

  Tea.start();

  return Tea.event.bind(Tea);
}

export { createTracker };
